// Validate and extract incoming payload
const body = $input.first().json.body ?? $input.first().json;

const hedge_ratio = parseFloat(body.hedge_ratio ?? 0.65);
const consumption = parseInt(body.consumption_bbl ?? 100000);
const instruments = body.instruments ?? ['futures'];
const current_var = parseFloat(body.current_var_usd ?? 0);
const what_if_result = body.what_if_result ?? null;

// Validate
if (hedge_ratio < 0.30 || hedge_ratio > 0.80) {
  throw new Error(`Invalid hedge_ratio: ${hedge_ratio}. Must be 0.30–0.80.`);
}
if (consumption < 1000 || consumption > 10000000) {
  throw new Error(`Invalid consumption_bbl: ${consumption}`);
}
if (!what_if_result) {
  throw new Error('what_if_result is required. Call /analytics/what-if first.');
}

// Build context for GPT
const var_usd = what_if_result.what_if?.var_usd ?? 0;
const rawCollateralPct = what_if_result.what_if?.collateral_pct_of_reserves ?? 0;
const collateralPctNum = Number(rawCollateralPct);
// Normalize to percent (0-100). Accept either fraction (0-1) or percent input.
const collateral_pct = Number.isFinite(collateralPctNum)
  ? (collateralPctNum <= 1 ? collateralPctNum * 100 : collateralPctNum)
  : 0;
const var_better = what_if_result.comparison?.var_better ?? false;
const var_diff = Math.abs(what_if_result.comparison?.var_difference ?? 0);
const monthly_saving = what_if_result.comparison?.monthly_saving_vs_unhedged ?? 0;
const instrument_mix = what_if_result.what_if?.instrument_mix ?? {};

// Determine risk profile for narrative tone
const risk_profile = hedge_ratio >= 0.70 ? 'aggressive'
  : hedge_ratio >= 0.55 ? 'moderate'
  : 'conservative';

// Format instrument summary
const instrument_summary = Object.entries(instrument_mix)
  .filter(([, v]) => v > 0.01)
  .map(([k, v]) => `${k} ${(v * 100).toFixed(0)}%`)
  .join(', ');

return [{
  json: {
    validated: true,
    hedge_ratio,
    consumption,
    instruments,
    current_var,
    what_if_result,
    var_usd,
    collateral_pct,
    var_better,
    var_diff,
    monthly_saving,
    instrument_summary,
    risk_profile,
    hedged_bbl: Math.round(consumption * hedge_ratio),
    unhedged_bbl: Math.round(consumption * (1 - hedge_ratio)),
    timestamp: new Date().toISOString()
  }
}];

// Build the GPT prompt from validated data
const d = $input.first().json;

const systemPrompt = `You are a senior aviation treasury analyst advising the CFO of a mid-size airline. 
You communicate in plain English — no jargon, no formulas. 
You give direct, confident, actionable recommendations in 3 sentences maximum. 
You always anchor your advice to real dollar amounts and barrel volumes. 
You never say 'it depends' — you make a clear recommendation.`;

const userPrompt = `The CFO has configured the following fuel hedging strategy:

- Monthly fuel uplift: ${d.consumption.toLocaleString()} barrels
- Target hedge ratio: ${(d.hedge_ratio * 100).toFixed(0)}% (${d.risk_profile} profile)
- Hedged volume: ${d.hedged_bbl.toLocaleString()} bbl covered, ${d.unhedged_bbl.toLocaleString()} bbl exposed
- Instrument mix: ${d.instrument_summary || 'futures only'}
- Portfolio VaR at this strategy: $${(d.var_usd / 1_000_000).toFixed(2)}M
- Collateral required: ${d.collateral_pct.toFixed(1)}% of reserves
- Monthly saving vs. fully unhedged: $${(d.monthly_saving / 1_000_000).toFixed(2)}M
- Compared to system recommendation: this strategy ${d.var_better ? 'reduces' : 'increases'} VaR by $${(d.var_diff / 1_000_000).toFixed(2)}M

Write a 3-sentence CFO briefing that:
1. States clearly whether this strategy is appropriate and why
2. Highlights the most important risk or opportunity in this specific configuration
3. Gives one concrete action recommendation

Do not use bullet points. Write in flowing prose. Be direct.`;

return [{
  json: {
    ...d,
    system_prompt: systemPrompt,
    user_prompt: userPrompt
  }
}];

// Extract GPT response and build final output
const gptResponse = $input.first().json;
const ctx = $('Prompt Builder').first().json;

// Extract narrative from model response
let narrative = '';
try {
  narrative = gptResponse.choices?.[0]?.message?.content?.trim() ?? '';
} catch (e) {
  narrative = '';
}

const usedGroqModel = Boolean(gptResponse?.choices?.[0]?.message?.content);

// Fallback narrative if model fails or returns empty
if (!narrative || narrative.length < 20) {
  const saving_m = (ctx.monthly_saving / 1_000_000).toFixed(2);
  const var_m = (ctx.var_usd / 1_000_000).toFixed(2);
  const direction = ctx.var_better ? 'reduces' : 'increases';

  narrative = `Hedging ${(ctx.hedge_ratio * 100).toFixed(0)}% of your ${ctx.consumption.toLocaleString()} bbl monthly uplift ` +
    `using ${ctx.instrument_summary || 'futures'} produces a portfolio VaR of $${var_m}M — ` +
    `this ${direction} risk by $${(ctx.var_diff / 1_000_000).toFixed(2)}M versus the system recommendation. ` +
    `At current prices, this strategy saves approximately $${saving_m}M per month compared to remaining fully unhedged. ` +
    `Collateral of ${ctx.collateral_pct.toFixed(1)}% of reserves is required — ` +
    `${ctx.collateral_pct > 12 ? 'approaching the 12% soft warning threshold' : 'within the acceptable 15% limit'}.`;
}

// Build the complete response
const response = {
  success: true,
  narrative,
  what_if: ctx.what_if_result?.what_if ?? {},
  comparison: ctx.what_if_result?.comparison ?? {},
  strategy_summary: {
    hedge_ratio: ctx.hedge_ratio,
    hedge_ratio_pct: `${(ctx.hedge_ratio * 100).toFixed(0)}%`,
    consumption_bbl: ctx.consumption,
    hedged_bbl: ctx.hedged_bbl,
    unhedged_bbl: ctx.unhedged_bbl,
    instrument_summary: ctx.instrument_summary,
    risk_profile: ctx.risk_profile,
    var_usd: ctx.var_usd,
    collateral_pct: ctx.collateral_pct,
    monthly_saving_usd: ctx.monthly_saving
  },
  generated_at: new Date().toISOString(),
  model_used: usedGroqModel ? 'groq_llama-3.3-70b-versatile' : 'fallback'
};

return [{ json: response }];
